import csv

questions = [
  {"id":"3861","tipo":"multipla","disciplina":"Matemática","tema":"Funções","subtema":"Composição de Funções","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Se f(x) = 2x + 1 e g(x) = x², qual é (f∘g)(3)?","alternativa_a":"19","alternativa_b":"49","alternativa_c":"7","alternativa_d":"37","alternativa_e":"10","resposta_correta":"a","explicacao":"(f∘g)(x) = f(g(x)). g(3) = 9. f(9) = 2(9) + 1 = 19.","resposta":""},
  {"id":"3862","tipo":"multipla","disciplina":"Física","tema":"Mecânica","subtema":"Oscilação","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"O período de um pêndulo simples depende de:","alternativa_a":"Comprimento do fio e aceleração gravitacional (T = 2π√(L/g))","alternativa_b":"Massa do peso e gravidade","alternativa_c":"Amplitude e gravidade","alternativa_d":"Comprimento e massa","alternativa_e":"Gravidade e amplitude","resposta_correta":"a","explicacao":"T = 2π√(L/g). O período depende apenas do comprimento L e da gravidade g — NÃO da massa nem da amplitude (para pequenas amplitudes). Galileu observou essa propriedade (isocronismo) num pêndulo de catedral.","resposta":""},
  {"id":"3863","tipo":"multipla","disciplina":"Química","tema":"Orgânica","subtema":"Açúcares","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"A lactose, presente no leite, é um dissacarídeo formado por:","alternativa_a":"Glicose + galactose","alternativa_b":"Glicose + frutose","alternativa_c":"Dois monômeros de glicose","alternativa_d":"Frutose + galactose","alternativa_e":"Glicose + ribose","resposta_correta":"a","explicacao":"Dissacarídeos e suas composições: sacarose = glicose + frutose; lactose = glicose + galactose; maltose = glicose + glicose. A intolerância à lactose é a incapacidade de digerir a lactose por deficiência da enzima lactase.","resposta":""},
  {"id":"3864","tipo":"multipla","disciplina":"Biologia","tema":"Virologia","subtema":"HIV","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"O HIV (vírus da AIDS) é um retrovírus que ataca principalmente:","alternativa_a":"Linfócitos T CD4+ (células auxiliares do sistema imune)","alternativa_b":"Hemácias (glóbulos vermelhos)","alternativa_c":"Plaquetas","alternativa_d":"Neurônios","alternativa_e":"Células musculares","resposta_correta":"a","explicacao":"O HIV infecta linfócitos T CD4+ (auxiliares), macrófagos e células dendríticas. Usa a enzima transcriptase reversa para converter seu RNA em DNA e integrar ao genoma da célula hospedeira. A destruição progressiva dos CD4+ leva à imunodeficiência (AIDS), tornando o indivíduo suscetível a infecções oportunistas.","resposta":""},
  {"id":"3865","tipo":"multipla","disciplina":"História","tema":"Contemporânea","subtema":"Globalização Cultural","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"A 'americanização' da cultura global refere-se a:","alternativa_a":"A disseminação mundial de produtos culturais, valores e estilos de vida norte-americanos","alternativa_b":"A influência americana exclusiva na política","alternativa_c":"A exportação de tecnologia militar dos EUA","alternativa_d":"A imigração em massa para os EUA","alternativa_e":"A dolarização das economias mundiais","resposta_correta":"a","explicacao":"A americanização cultural inclui: Hollywood (cinema), fast food (McDonald's), redes sociais (Meta, Google), músicas (pop, rap), marcas de roupas (Nike, Levi's), séries de TV. Críticos apontam que essa padronização ameaça culturas locais; outros argumentam que há hibridização — culturas locais reinterpretam a cultura americana.","resposta":""},
  {"id":"3866","tipo":"multipla","disciplina":"Geografia","tema":"Geopolítica","subtema":"Migração","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"A crise migratória europeia de 2015-16 teve como principal origem:","alternativa_a":"A guerra civil na Síria e conflitos no Oriente Médio e na África","alternativa_b":"Crise econômica nos países europeus","alternativa_c":"Epidemia na África Subsaariana","alternativa_d":"Conflito entre Rússia e Ucrânia","alternativa_e":"Tsunami no Mediterrâneo","resposta_correta":"a","explicacao":"A crise migratória europeia de 2015-16 foi impulsionada principalmente pela guerra civil síria (desde 2011), que gerou mais de 5 milhões de refugiados. Também contribuíram conflitos no Afeganistão, Iraque, Eritreia e Líbia. Mais de 1 milhão de pessoas tentaram entrar na Europa via Mediterrâneo, gerando debates sobre políticas de asilo e xenofobia.","resposta":""},
  {"id":"3867","tipo":"multipla","disciplina":"Língua Portuguesa","tema":"Literatura","subtema":"Trovadorismo","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"O Trovadorismo, primeira manifestação literária em língua portuguesa (séc. XII-XIV), divide-se em lírico e satírico. O gênero lírico feminino em que a mulher lamenta a ausência do amado é a:","alternativa_a":"Cantiga de amigo","alternativa_b":"Cantiga de amor","alternativa_c":"Cantiga de escárnio","alternativa_d":"Cantiga de maldizer","alternativa_e":"Pastorela","resposta_correta":"a","explicacao":"Gêneros trovadorescos: Cantiga de amigo: voz feminina (a moça que fala do 'amigo'/amado ausente). Cantiga de amor: voz masculina (o trovador que adora a dama — amor cortês). Cantiga de escárnio: sátira indireta com duplo sentido. Cantiga de maldizer: sátira direta e explícita.","resposta":""},
  {"id":"3868","tipo":"multipla","disciplina":"Filosofia","tema":"Filosofia Social","subtema":"Gramsci","dificuldade":"Difícil","fonte":"Vestibular","ano":"2024","enunciado":"Antonio Gramsci introduziu o conceito de 'hegemonia' para explicar:","alternativa_a":"Como a classe dominante mantém seu poder por meio do consenso cultural e ideológico, não só pela força","alternativa_b":"A dominação puramente militar das classes subordinadas","alternativa_c":"O controle econômico direto dos meios de produção","alternativa_d":"A conquista militar de territórios por potências imperialistas","alternativa_e":"A democracia direta como forma de poder popular","resposta_correta":"a","explicacao":"Gramsci (Cadernos do Cárcere, 1930s) propôs que o poder capitalista se sustenta tanto pela coerção (Estado, exército, polícia) quanto pelo consenso — hegemonia: a classe dominante lidera ideologicamente a sociedade, fazendo que suas visões de mundo sejam aceitas como naturais pelos dominados. A contra-hegemonia (resistência) passa pela disputa cultural e pela construção de um bloco histórico alternativo.","resposta":""},
  {"id":"3869","tipo":"multipla","disciplina":"Sociologia","tema":"Meio Ambiente","subtema":"Justiça Ambiental","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Justiça ambiental é o princípio que defende:","alternativa_a":"A distribuição equitativa dos benefícios e dos riscos ambientais, sem discriminação de raça ou renda","alternativa_b":"A preservação exclusiva das áreas naturais sem uso humano","alternativa_c":"O direito das empresas a poluir mediante pagamento de taxas","alternativa_d":"A transferência dos problemas ambientais para países em desenvolvimento","alternativa_e":"A privatização dos recursos naturais para gestão mais eficiente","resposta_correta":"a","explicacao":"Justiça ambiental (movimento surgido nos EUA, 1980s): a exposição a riscos ambientais (poluição, lixões, instalações tóxicas) é desigual — recai desproporcionalmente sobre comunidades pobres e negras. No Brasil: populações indígenas, quilombolas e periferias urbanas são as mais afetadas por desastres e poluição. A justiça ambiental exige que nenhum grupo suporte fardos ambientais desproporcionais.","resposta":""},
  {"id":"3870","tipo":"multipla","disciplina":"Matemática","tema":"Matrizes","subtema":"Matriz Identidade","dificuldade":"Fácil","fonte":"Vestibular","ano":"2024","enunciado":"A matriz identidade de ordem 2 é:","alternativa_a":"[[1,0],[0,1]]","alternativa_b":"[[0,0],[0,0]]","alternativa_c":"[[1,1],[1,1]]","alternativa_d":"[[2,0],[0,2]]","alternativa_e":"[[0,1],[1,0]]","resposta_correta":"a","explicacao":"A matriz identidade I_n tem 1 na diagonal principal e 0 em todas as outras posições. I₂ = [[1,0],[0,1]]. Propriedade: A × I = I × A = A para qualquer matriz A de mesma ordem.","resposta":""},
  {"id":"3871","tipo":"multipla","disciplina":"Física","tema":"Ondas","subtema":"Polarização da Luz","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"A polarização da luz é possível apenas para:","alternativa_a":"Ondas transversais (como a luz)","alternativa_b":"Ondas longitudinais (como o som)","alternativa_c":"Qualquer tipo de onda","alternativa_d":"Apenas ondas sonoras","alternativa_e":"Ondas de rádio apenas","resposta_correta":"a","explicacao":"Polarização: processo pelo qual as vibrações de uma onda transversal são restritas a um único plano. Só ondas transversais podem ser polarizadas (vibrações perpendiculares à propagação). Ondas longitudinais (som) não são polarizáveis — as vibrações são paralelas à propagação. Aplicações: óculos polaroid, telas de LCD, câmeras fotográficas.","resposta":""},
  {"id":"3872","tipo":"multipla","disciplina":"Química","tema":"Orgânica","subtema":"Terpenos","dificuldade":"Difícil","fonte":"Vestibular","ano":"2024","enunciado":"Os terpenos são compostos orgânicos derivados do isopreno (C₅H₈). São responsáveis por:","alternativa_a":"Aromas de plantas (essências), borracha natural e carotenoides","alternativa_b":"A acidez das frutas","alternativa_c":"O sabor doce do açúcar","alternativa_d":"A cor verde da clorofila","alternativa_e":"A fermentação alcoólica","resposta_correta":"a","explicacao":"Terpenos: polímeros de isopreno com funções diversas. Monoterpenos (C₁₀): aromas de limão (limoneno), menta (mentol). Sesquiterpenos (C₁₅): óleo de gengibre. Diterpenos (C₂₀): vitamina A. Triterpenos (C₃₀): colesterol, hormônios esteroides. Tetraterpenos (C₄₀): carotenoides (betacaroteno). Politerpenos: borracha natural (poliisopreno).","resposta":""},
  {"id":"3873","tipo":"multipla","disciplina":"Biologia","tema":"Genética","subtema":"Mapa Cromossômico","dificuldade":"Difícil","fonte":"Vestibular","ano":"2024","enunciado":"No mapeamento cromossômico, a unidade de recombinação cM (centimorgan) representa:","alternativa_a":"1% de frequência de recombinação entre dois loci — quanto maior, mais distantes os genes no cromossomo","alternativa_b":"O número de pares de bases entre dois genes","alternativa_c":"A taxa de mutação espontânea por geração","alternativa_d":"A distância física em nanômetros entre genes","alternativa_e":"A porcentagem de expressão do gene","resposta_correta":"a","explicacao":"O centimorgan (cM) ou unidade de mapa genético: 1 cM = 1% de frequência de recombinação (crossing-over) entre dois loci. Quanto mais distantes os genes no cromossomo, maior a probabilidade de crossing-over entre eles, maior a frequência de recombinação e maior a distância em cM. Genes a >50 cM de distância segregam independentemente (lei de Mendel).","resposta":""},
  {"id":"3874","tipo":"multipla","disciplina":"História","tema":"Brasil","subtema":"Estatuto da Igualdade Racial","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"O Estatuto da Igualdade Racial (Lei 12.288/2010) foi criado para:","alternativa_a":"Combater a discriminação racial e promover igualdade de oportunidades para afrodescendentes","alternativa_b":"Criar reservas indígenas no Nordeste","alternativa_c":"Criminalizar qualquer discussão sobre raça no Brasil","alternativa_d":"Privatizar terras de quilombos","alternativa_e":"Estabelecer cotas apenas no serviço público federal","resposta_correta":"a","explicacao":"O Estatuto da Igualdade Racial reconhece a discriminação racial como realidade histórica e estrutural no Brasil e estabelece: direito à saúde, educação, cultura, esporte, lazer e acesso à terra da população negra; cotas em universidades e serviço público; e políticas afirmativas para combater desigualdades raciais.","resposta":""},
  {"id":"3875","tipo":"multipla","disciplina":"Língua Portuguesa","tema":"Gramática","subtema":"Semântica","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"'Vou sair agora.' vs 'Vou sair já.' — 'agora' e 'já' são:","alternativa_a":"Advérbios de tempo com sentidos próximos (imediatamente/neste momento)","alternativa_b":"Conjunções temporais","alternativa_c":"Preposições de tempo","alternativa_d":"Pronomes temporais","alternativa_e":"Verbos no gerúndio","resposta_correta":"a","explicacao":"'Agora' e 'já' são advérbios de tempo. 'Agora' = neste momento. 'Já' = imediatamente / neste momento (nuance de urgência). Ambos modificam o verbo indicando o momento da ação. Advérbios modificam verbos, adjetivos ou outros advérbios.","resposta":""},
  {"id":"3876","tipo":"multipla","disciplina":"Filosofia","tema":"Filosofia Contemporânea","subtema":"Bauman","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Zygmunt Bauman desenvolveu o conceito de 'modernidade líquida' para descrever:","alternativa_a":"A fluidez, instabilidade e impermanência das relações, identidades e instituições na sociedade contemporânea","alternativa_b":"A solidez das normas sociais na sociedade industrial","alternativa_c":"A rigidez burocrática do Estado moderno","alternativa_d":"A liquidez financeira dos mercados de capitais","alternativa_e":"A dissolução do Estado-nação no mercado global","resposta_correta":"a","explicacao":"Bauman ('Modernidade Líquida', 2000) contrapõe a 'modernidade sólida' (relações fixas, identidades estáveis, instituições duradouras) à 'modernidade líquida': tudo flui, nenhuma relação é permanente (empregos, vínculos afetivos, identidades, ideologias). Gera liberdade mas também insegurança, ansiedade e solidão. A metáfora da liquidez captura a efemeridade da contemporaneidade.","resposta":""},
  {"id":"3877","tipo":"multipla","disciplina":"Matemática","tema":"Teoria dos Números","subtema":"Números Primos","dificuldade":"Fácil","fonte":"Vestibular","ano":"2024","enunciado":"Quais dos números abaixo são TODOS primos?","alternativa_a":"2, 3, 5, 7","alternativa_b":"1, 2, 3, 5","alternativa_c":"2, 4, 5, 7","alternativa_d":"3, 6, 7, 11","alternativa_e":"1, 3, 5, 9","resposta_correta":"a","explicacao":"Números primos têm exatamente dois divisores: 1 e eles mesmos. 1 não é primo (um único divisor). 4 = 2×2 (composto). 6 = 2×3 (composto). 9 = 3×3 (composto). 2, 3, 5 e 7 são todos primos.","resposta":""},
  {"id":"3878","tipo":"multipla","disciplina":"Química","tema":"Inorgânica","subtema":"Amônia","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"O processo industrial de síntese da amônia (N₂ + 3H₂ → 2NH₃) é chamado de:","alternativa_a":"Processo Haber-Bosch","alternativa_b":"Processo Solvay","alternativa_c":"Destilação fracionada","alternativa_d":"Processo Hall-Héroult","alternativa_e":"Processo Frasch","resposta_correta":"a","explicacao":"O processo Haber-Bosch (Fritz Haber e Carl Bosch, início do séc. XX) fixa o nitrogênio atmosférico em amônia usando catalisador de ferro, alta temperatura (~400-500°C) e alta pressão (150-300 atm). A amônia é base para fertilizantes nitrogenados — responsável por sustentar cerca de metade da população mundial ao aumentar a produção agrícola.","resposta":""},
  {"id":"3879","tipo":"multipla","disciplina":"Biologia","tema":"Botânica","subtema":"Pteridófitas","dificuldide":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"As samambaias pertencem ao grupo das pteridófitas, que são plantas vasculares mas:","alternativa_a":"Sem sementes — reproduzem-se por esporos","alternativa_b":"Com sementes nuas","alternativa_c":"Com flores e frutos","alternativa_d":"Exclusivamente marinhas","alternativa_e":"Sem vasos condutores","resposta_correta":"a","explicacao":"Pteridófitas (samambaias, cavalinhas, licopódios): têm xilema e floema (vasculares) mas NÃO têm sementes — reproduzem-se por esporos. Sua reprodução ainda depende de água para o deslocamento dos anterozoides. Diferente das espermatófitas (gimnospermas e angiospermas), que têm sementes.","resposta":""},
  {"id":"3880","tipo":"multipla","disciplina":"Geografia","tema":"Desenvolvimento","subtema":"Cooperação Internacional","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"A ODA (Ajuda Oficial ao Desenvolvimento) é:","alternativa_a":"Transferência de recursos dos países ricos para países em desenvolvimento para fins de desenvolvimento","alternativa_b":"Um empréstimo comercial do FMI","alternativa_c":"Investimento estrangeiro direto em países emergentes","alternativa_d":"Uma sanção econômica da ONU","alternativa_e":"Um acordo de livre comércio","resposta_correta":"a","explicacao":"ODA (Official Development Assistance): transferências financeiras concessionais (doações ou empréstimos com condições favoráveis) de países desenvolvidos a países em desenvolvimento, para fins de desenvolvimento econômico e bem-estar. Os países da OCDE comprometeram-se a destinar 0,7% do PIB para ODA (poucos alcançam). Debate: eficácia da ajuda vs. dependência gerada.","resposta":""},
  {"id":"4561","tipo":"dissertativa","disciplina":"Matemática","tema":"Sequências","subtema":"Recursividade","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"A sequência de Lucas começa: 2, 1, 3, 4, 7, 11, ... (cada termo é a soma dos dois anteriores, como Fibonacci, mas começa com 2 e 1). Calcule os próximos 3 termos e explique a diferença com Fibonacci.","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Regra: Lₙ = Lₙ₋₁ + Lₙ₋₂. Continuando: 11+7 = 18; 18+11 = 29; 29+18 = 47. Próximos termos: 18, 29, 47. Diferença com Fibonacci: ambas usam a mesma recorrência (cada termo = soma dos dois anteriores), mas têm valores iniciais diferentes: Fibonacci: F₁=1, F₂=1 (ou F₀=0, F₁=1); Lucas: L₁=2, L₂=1. A razão entre termos consecutivos de ambas converge para φ (número áureo ≈ 1,618), chamado de razão áurea.","resposta":"18, 29, 47 — mesma recorrência de Fibonacci, mas começa com 2 e 1; ambas convergem para a razão áurea φ ≈ 1,618"},
  {"id":"4562","tipo":"dissertativa","disciplina":"Física","tema":"Termodinâmica","subtema":"Ciclo de Carnot","dificuldade":"Difícil","fonte":"Vestibular","ano":"2024","enunciado":"Explique por que o ciclo de Carnot representa o máximo rendimento teórico para uma máquina térmica e quais suas limitações práticas.","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"O ciclo de Carnot (Nicolas Carnot, 1824) é composto por 4 processos reversíveis: duas isotermas (absorção/rejeição de calor) e dois adiabáticos. Seu rendimento máximo: η = 1 − T_fria/T_quente. É o máximo teórico pela 2ª Lei da Termodinâmica: nenhuma máquina real pode ter rendimento maior do que a de Carnot entre as mesmas temperaturas. Limitações práticas: (1) Processos reais são irreversíveis (atrito, condução de calor real) — o ciclo de Carnot é ideal; (2) Operação extremamente lenta para que os processos sejam reversíveis; (3) Temperaturas práticas limitadas pelos materiais. Motores reais (a vapor, a combustão) têm rendimentos de 20-40%.","resposta":"Carnot é o máximo teórico (η = 1 − T₂/T₁) pela 2ª Lei; na prática, processos irreversíveis, fricção e limites de temperatura reduzem drasticamente o rendimento"},
  {"id":"4563","tipo":"dissertativa","disciplina":"Química","tema":"Química Computacional","subtema":"Modelos Moleculares","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Qual é a importância dos modelos moleculares na química e como a geometria molecular influencia as propriedades das substâncias?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Modelos moleculares (VSEPR, mecânica quântica, modelagem computacional) permitem prever a geometria tridimensional das moléculas com base na repulsão dos pares de elétrons. A geometria molecular determina: (1) Polaridade: H₂O (angular, polar) vs. CO₂ (linear, apolar) — apesar de ambas terem ligações polares; (2) Ponto de ebulição: moléculas polares têm interações mais fortes → maior PE; (3) Solubilidade: 'semelhante dissolve semelhante'; (4) Atividade biológica: a forma da molécula determina se ela encaixa no receptor (chave-fechadura). Ex.: talidomida — os dois enantiômeros têm mesma fórmula mas geometrias espelhadas, com efeitos biológicos opostos.","resposta":"Geometria molecular (VSEPR) determina polaridade, ponto de ebulição, solubilidade e atividade biológica — forma molda função"},
  {"id":"4564","tipo":"dissertativa","disciplina":"Biologia","tema":"Saúde Pública","subtema":"Epidemiologia","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Explique as diferenças entre endemia, epidemia e pandemia, com um exemplo de cada.","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Endemia: doença que ocorre regularmente em determinada região geográfica, com incidência previsível e controlada. Ex.: malária na Amazônia brasileira, doença de Chagas no sertão nordestino. Epidemia: aumento súbito e inesperado de casos de uma doença além do esperado para uma região. Ex.: surto de dengue em São Paulo em 2024. Pandemia: epidemia que se espalha por múltiplos países ou continentes, afetando grande parte da população mundial. Ex.: COVID-19 (2020), gripe espanhola (1918), HIV/AIDS (desde 1980s). A distinção é de escala geográfica e magnitude, não de gravidade intrínseca da doença.","resposta":"Endemia: doença local regular (malária na Amazônia). Epidemia: surto regional inesperado (dengue). Pandemia: espalhamento global (COVID-19)"},
  {"id":"4565","tipo":"dissertativa","disciplina":"História","tema":"Brasil","subtema":"Identidade Nacional","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Gilberto Freyre, em 'Casa-Grande & Senzala' (1933), defendeu a 'democracia racial' no Brasil. Discuta essa tese e sua crítica contemporânea.","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Gilberto Freyre argumentou que a miscigenação entre brancos, negros e indígenas teria criado uma sociedade única, onde a convivência racial seria mais harmoniosa do que em outros países (especialmente os EUA com segregação formal). O Brasil seria uma 'democracia racial'. Críticas contemporâneas: (1) O mito da democracia racial mascara o racismo estrutural e as desigualdades reais entre brancos e negros; (2) A miscigenação não eliminou a hierarquia racial — negros continuam sub-representados no topo e super-representados na base da pirâmide social; (3) Florestan Fernandes ('A Integração do Negro na Sociedade de Classes', 1964) demonstrou empiricamente a persistência do racismo. A democracia racial é um mito que impede o reconhecimento e o combate ao racismo.","resposta":"Freyre: miscigenação criou harmonia racial única. Crítica: mascara racismo estrutural real e desigualdades persistentes — Florestan Fernandes refutou empiricamente"},
  {"id":"4566","tipo":"dissertativa","disciplina":"Língua Portuguesa","tema":"Literatura","subtema":"Autoficcção","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"O que é autoficção na literatura contemporânea? Cite um autor que utilize esse recurso.","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Autoficção é um gênero literário híbrido que mistura autobiografia e ficção: o autor usa sua própria vida como matéria-prima mas constrói personagens e narrativas ficcionais sobre essa base. Diferente da autobiografia (compromisso com a verdade factual) e do romance tradicional (personagem claramente fictício). O termo foi cunhado pelo francês Serge Doubrovsky (1977). No Brasil: Bernardo Carvalho, Luiz Ruffato. Na literatura portuguesa contemporânea: Valter Hugo Mãe. Exemplo clássico: 'O Amante' de Marguerite Duras. A autoficção questiona os limites entre vida e literatura, eu e personagem.","resposta":"Autoficção: mistura autobiografia e ficção, com o autor como personagem de si mesmo. Exemplo: obras de Luiz Ruffato no Brasil; Doubrovsky cunhou o termo"},
  {"id":"4567","tipo":"dissertativa","disciplina":"Filosofia","tema":"Filosofia do Direito","subtema":"Positivismo Jurídico","dificuldade":"Difícil","fonte":"Vestibular","ano":"2024","enunciado":"Explique a diferença entre o positivismo jurídico de Kelsen e o jusnaturalismo. Qual a importância prática dessa distinção?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Positivismo jurídico (Hans Kelsen, 'Teoria Pura do Direito', 1934): o direito é um sistema de normas positivas (criadas pelo Estado), sem relação necessária com a moral ou a natureza. A validade de uma norma depende de ter sido criada por uma autoridade competente segundo procedimentos previstos — não de seu conteúdo moral. A norma fundamental (Grundnorm) é o pressuposto lógico do sistema. Jusnaturalismo: há uma ordem jurídica superior (razão, natureza, Deus) que valida ou invalida o direito positivo. Uma lei injusta não é lei (Lex iniusta non est lex — Agostinho). Importância prática: o jusnaturalismo embasou os Processos de Nuremberg (1945-46): réus nazistas alegaram que obedeciam às leis — foram condenados com base em 'crimes contra a humanidade' acima do direito positivo alemão.","resposta":"Kelsen: direito positivo válido pelo procedimento, não pelo conteúdo moral. Jusnaturalismo: lei injusta não é lei. Diferença foi crucial em Nuremberg"},
  {"id":"4568","tipo":"dissertativa","disciplina":"Sociologia","tema":"Desigualdade","subtema":"Interseccionalidade","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"O que é interseccionalidade e por que é importante para a análise das desigualdades sociais?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Interseccionalidade (Kimberlé Crenshaw, 1989): conceito que descreve como diferentes sistemas de opressão (raça, gênero, classe, sexualidade, deficiência) se intersectam e se reforçam mutuamente, criando experiências específicas de discriminação que não podem ser compreendidas analisando cada dimensão separadamente. Ex.: uma mulher negra pobre enfrenta opressões que não são simplesmente a soma de ser mulher + ser negra + ser pobre — há uma experiência específica de intersecção. Importância: supera análises monodimensionais, revela vulnerabilidades específicas, orienta políticas públicas mais inclusivas. É central nos estudos feministas, de raça e diversidade.","resposta":"Interseccionalidade: raça, gênero, classe etc. se cruzam criando opressões específicas que não são redutíveis a cada dimensão isolada — Kimberlé Crenshaw"},
  {"id":"4569","tipo":"dissertativa","disciplina":"Geografia","tema":"Brasil","subtema":"Nordeste","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Quais são os principais fatores históricos e naturais que explicam as desigualdades socioeconômicas do Nordeste brasileiro?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Fatores naturais: semiárido com chuvas irregulares e escassas, solo cristalino com baixa infiltração, recursos hídricos limitados — favorece secas cíclicas que arruinam colheitas e forçam migrações. Fatores históricos: (1) Economia colonial baseada no açúcar e no latifúndio monocultor (séculos XVI-XVIII) que concentrou terras; (2) Abolição sem reforma agrária: ex-escravizados sem terra ficaram dependentes dos coronéis; (3) Coronelismo e clientelismo político que perpetuaram elites locais e impedram reformas; (4) Industrialização concentrada no Sudeste (décadas de 1950-70) sem política de desenvolvimento regional. Programas como Sudene, Transposição do São Francisco e transferência de renda (Bolsa Família) buscaram reduzir as desigualdades.","resposta":"Semiárido + latifúndio colonial + abolição sem terra + coronelismo + industrialização concentrada no Sudeste são os fatores das desigualdades nordestinas"},
  {"id":"4570","tipo":"dissertativa","disciplina":"Matemática","tema":"Combinatória","subtema":"Princípio da Inclusão-Exclusão","dificuldade":"Difícil","fonte":"Vestibular","ano":"2024","enunciado":"Em uma turma de 30 alunos, 18 gostam de Matemática, 15 gostam de Física e 8 gostam de ambas. Quantos gostam de ao menos uma das duas disciplinas? Quantos não gostam de nenhuma?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Princípio da Inclusão-Exclusão: |A ∪ B| = |A| + |B| − |A ∩ B|. |Mat ∪ Fís| = 18 + 15 − 8 = 25. Gostam de ao menos uma: 25 alunos. Não gostam de nenhuma: 30 − 25 = 5 alunos. Esse princípio evita a contagem dupla dos elementos que pertencem a ambos os conjuntos.","resposta":"25 gostam de ao menos uma; 5 não gostam de nenhuma"},
]

